(function ($) {
  "use strict";

  /* ============================================================
   * Create / Edit Next Session Modal
   * Fixes:
   *  1. No double popup – removed loadingSwl(), show Swal once
   *  2. Kemetic dark theme applied to the popup
   *  3. Client-side validation before save
   * ============================================================ */

  $('body').off('click', '.js-webinar-next-session').on('click', '.js-webinar-next-session', function (e) {
    e.preventDefault();
    e.stopPropagation();                        // prevent any extra bubble events

    var $this      = $(this);
    var webinarId  = $this.attr('data-webinar-id');

    // Disable button while loading to prevent double-click
    $this.prop('disabled', true).css('opacity', '0.6');

    $.get('/panel/webinars/' + webinarId + '/getNextSessionInfo', function (result) {
      $this.prop('disabled', false).css('opacity', '');

      if (result && result.code === 200) {
        var session = result.session;
        var mainRow = $('#webinarNextSessionModal').clone();
        mainRow     = mainRow.prop('innerHTML');

        if (session !== null) {
          mainRow = mainRow.replace(/\[new\]/g, '[' + session.id + ']');
        }

        var $html = '<div id="webinarNextSessionHtml">' + mainRow + '</div>';

        Swal.fire({
          html: $html,
          showCancelButton: false,
          showConfirmButton: false,
          background: '#0f0f0f',
          customClass: {
            popup:   'kemetic-swal-popup',
            content: 'p-0 text-left'
          },
          width: '48rem',
          onOpen: function onOpen() {
            var $modal             = $('#webinarNextSessionHtml');
            var webinar_id_input_key = 'new';

            /* ---- Inject Kemetic styles into the SweetAlert popup ---- */
            if (!$('#kemetic-swal-style').length) {
              $('head').append(
                '<style id="kemetic-swal-style">' +
                '.kemetic-swal-popup { background:#0f0f0f!important; border:1px solid rgba(242,201,76,.25)!important; border-radius:18px!important; }' +
                '.kemetic-swal-popup .swal2-content { color:#e6e6e6!important; }' +
                '.kemetic-swal-popup h3.section-title { color:#F2C94C!important; font-size:18px; font-weight:700; }' +
                '.kemetic-swal-popup .input-label { color:#F2C94C!important; font-size:13px; font-weight:600; }' +
                '.kemetic-swal-popup .form-control { background:#101010!important; border:1px solid #2a2a2a!important; border-radius:10px!important; color:#e6e6e6!important; padding:10px 14px; }' +
                '.kemetic-swal-popup .form-control:focus { border-color:#F2C94C!important; box-shadow:0 0 0 2px rgba(242,201,76,.18)!important; }' +
                '.kemetic-swal-popup .input-group-text { background:#1a1a1a!important; border:1px solid #2a2a2a!important; color:#F2C94C!important; border-radius:10px 0 0 10px!important; }' +
                '.kemetic-swal-popup .btn-primary { background:linear-gradient(135deg,#F2C94C,#E5A100)!important; border:none!important; color:#000!important; border-radius:12px!important; font-weight:700; padding:10px 24px; }' +
                '.kemetic-swal-popup .btn-primary:hover { box-shadow:0 8px 20px rgba(242,201,76,.4)!important; transform:translateY(-1px); }' +
                '.kemetic-swal-popup .btn-danger { background:transparent!important; border:1px solid #444!important; color:#ccc!important; border-radius:12px!important; padding:10px 24px; }' +
                '.kemetic-swal-popup .btn-danger:hover { background:#1f1f1f!important; color:#fff!important; }' +
                '.kemetic-swal-popup .invalid-feedback { color:#ff6b6b!important; font-size:12px; }' +
                '.kemetic-swal-popup select.form-control option { background:#101010; color:#e6e6e6; }' +
                '</style>'
              );
            }

            /* ---- Populate existing session data ---- */
            if (session !== null) {
              $modal.find('form').attr('action', '/panel/sessions/' + session.id + '/update');
              Object.keys(session).forEach(function (key) {
                $modal.find('[name="ajax[' + session.id + '][' + key + ']"]').val(session[key]);
              });
              $modal.find('[name="ajax[' + session.id + '][status]"]').val(session.status === 'active' ? 'on' : null);

              if (session.agora_settings) {
                $modal.find('[name="ajax[' + session.id + '][agora_chat]"]').val(session.agora_settings.chat   ? 'on' : null);
                $modal.find('[name="ajax[' + session.id + '][agora_rec]"]').val(session.agora_settings.record  ? 'on' : null);
              }

              webinar_id_input_key = session.id;
            }

            $modal.find('[name="ajax[' + webinar_id_input_key + '][webinar_id]"]').val(result.webinar_id);

            /* ---- Disable fields for non-local sessions ---- */
            if (session && session.session_api !== 'local') {
              $modal.find('[name="ajax[' + session.id + '][session_api]"]').prop('disabled', true);
              $modal.find('[name="ajax[' + session.id + '][api_secret]"]').prop('disabled', true);
              $modal.find('[name="ajax[' + session.id + '][link]"]').prop('disabled', true);
              $modal.find('[name="ajax[' + session.id + '][date]"]').prop('disabled', true);
              $modal.find('[name="ajax[' + session.id + '][duration]"]').prop('disabled', true);
            }

            if (session && session.session_api === 'big_blue_button') {
              $modal.find('.js-moderator-secret').removeClass('d-none');
              $modal.find('[name="ajax[' + session.id + '][moderator_secret]"]').prop('disabled', true);
            } else {
              $modal.find('.js-moderator-secret').addClass('d-none');
            }

            if (session && (session.session_api === 'zoom' || session.session_api === 'agora' || session.session_api === 'jitsi')) {
              $modal.find('.js-api-secret').addClass('d-none');
            }

            /* ---- Populate chapter dropdown ---- */
            var $chapterSelection = $modal.find('.js-ajax-chapter_id');
            if (result && result.chapters) {
              var html = '<option value="">' + selectChapterLang + '</option>';
              Object.keys(result.chapters).forEach(function (key) {
                var chapter = result.chapters[key];
                html += '<option value="' + chapter.id + '">' + chapter.title + '</option>';
              });
              $chapterSelection.html(html);
            }

            resetDatePickers();
          }
        });

      }
    }).fail(function (err) {
      $this.prop('disabled', false).css('opacity', '');
      Swal.fire({
        icon: 'error',
        html: '<h3 class="font-20 text-center py-25" style="color:#F2C94C">' + undefinedActiveSessionLang + '</h3>',
        showConfirmButton: false,
        background: '#0f0f0f',
        customClass: { popup: 'kemetic-swal-popup' }
      });
    });
  });

  /* ============================================================
   * Save Next Session — with client-side validation
   * ============================================================ */
  $('body').off('click', '.js-save-next-session').on('click', '.js-save-next-session', function (e) {
    e.preventDefault();
    var $this = $(this);
    var form  = $this.closest('form');

    /* --- Client-side validation --- */
    form.find('.is-invalid').removeClass('is-invalid');
    form.find('.invalid-feedback').text('');
    var hasError = false;

    var titleField = form.find('.js-ajax-title');
    if (titleField.length && !titleField.val().trim()) {
      titleField.addClass('is-invalid');
      titleField.parent().find('.invalid-feedback').text('Session title is required.');
      hasError = true;
    }

    var dateField = form.find('.js-ajax-date');
    if (dateField.length && !dateField.val().trim()) {
      dateField.addClass('is-invalid');
      dateField.parent().find('.invalid-feedback').text('Date is required.');
      hasError = true;
    }

    var durationField = form.find('.js-ajax-duration');
    if (durationField.length && !durationField.val().trim()) {
      durationField.addClass('is-invalid');
      durationField.parent().find('.invalid-feedback').text('Duration is required.');
      hasError = true;
    }

    if (hasError) {
      return false;
    }

    var data   = serializeObjectByTag(form);
    var action = form.attr('action');
    $this.addClass('loadingbar primary').prop('disabled', true);
    form.find('input').removeClass('is-invalid');
    form.find('textarea').removeClass('is-invalid');

    $.post(action, data, function (result) {
      if (result && result.code === 200) {
        Swal.fire({
          icon: 'success',
          html: '<h3 class="font-20 text-center py-25" style="color:#F2C94C">' + saveSuccessLang + '</h3>',
          showConfirmButton: false,
          background: '#0f0f0f',
          customClass: { popup: 'kemetic-swal-popup' },
          width: '25rem'
        });
        setTimeout(function () {
          window.location.reload();
        }, 500);
      }
    }).fail(function (err) {
      $this.removeClass('loadingbar primary').prop('disabled', false);
      var errors = err.responseJSON;

      if (errors && errors.errors) {
        Object.keys(errors.errors).forEach(function (key) {
          var error   = errors.errors[key];
          var element = form.find('.js-ajax-' + key);
          element.addClass('is-invalid');
          element.parent().find('.invalid-feedback').text(error[0]);
        });
      }
    });
  });

  /* ============================================================
   * Session API selector — toggle visible inputs
   * ============================================================ */
  $('body').on('change', '.js-ajax-session_api', function (e) {
    e.preventDefault();
    var sessionForm = $(this).closest('form');
    var value       = this.value;

    if (value === 'big_blue_button') {
      sessionForm.find('.js-local-link').addClass('d-none');
      sessionForm.find('.js-api-secret').removeClass('d-none');
      sessionForm.find('.js-moderator-secret').removeClass('d-none');
    } else if (value === 'zoom') {
      sessionForm.find('.js-local-link').addClass('d-none');
      sessionForm.find('.js-api-secret').addClass('d-none');
      sessionForm.find('.js-moderator-secret').addClass('d-none');
    } else if (value === 'agora') {
      sessionForm.find('.js-local-link').addClass('d-none');
      sessionForm.find('.js-api-secret').addClass('d-none');
      sessionForm.find('.js-moderator-secret').addClass('d-none');
    } else if (value === 'jitsi') {
      sessionForm.find('.js-local-link').addClass('d-none');
      sessionForm.find('.js-api-secret').addClass('d-none');
      sessionForm.find('.js-moderator-secret').addClass('d-none');
    } else {
      sessionForm.find('.js-local-link').removeClass('d-none');
      sessionForm.find('.js-api-secret').removeClass('d-none');
      sessionForm.find('.js-moderator-secret').addClass('d-none');
    }
  });

  /* ============================================================
   * Switches
   * ============================================================ */
  $('body').on('change', '#conductedSwitch', function (e) {
    e.preventDefault();
    $(this).closest('form').trigger('submit');
  });
  $('body').on('change', '#freeClassesSwitch', function (e) {
    e.preventDefault();
    $(this).closest('form').trigger('submit');
  });

})(jQuery);
